import React from 'react'
import './Intro.css'
import Github from '../../images/github.png';
import Linkedin from '../../images/linkedin.png';
import Profilepic from '../../images/Profilepic.jfif';
import { themeContext } from '../../Context';
import { useContext } from 'react';
import {Link} from 'react-scroll'


const Intro = () => {
    const theme = useContext(themeContext);
    const darkMode = theme.state.darkMode;
  return (
    <div className="intro" id="home" class="nav-link home">
        <div className='i-left'>
            <div className='i-name' 
            id="user-detail-name"
            >
                <span style={{color: darkMode ? 'white' : ''}}>Hi! I am</span>
                <span>Vishwajeet Singh</span>
                <span id="user-detail-intro"
                >Full Stack Web Developer with expertise in MERN stack. Problem solver and good communicator eager to prove my value and talent at an emerging company. Motivated to advance and expand my skill set through targeted metorship and challenging projects.</span>
            </div>
            <Link spy={true} to='contact' smooth={true}  activeClass="activeClass">
                <button className='button i-button'>Contact</button>
            </Link>
            <div className="i-icons">
                <a href="https://github.com/vishwajeet-7" target="_blank">
                    <img src={Github} alt="" id="contact-github"/>
                </a>
                <a href="https://www.linkedin.com/in/vishady7" target="_blank">
                <img src={Linkedin} alt="" id="contact-linkedin"/>
                </a>
            </div>
        </div>
        <div className='i-right'>
            {/* <img src={glassesimoji} alt="" /> */}
            <img class="home-img" src={Profilepic} alt="Profile-pic" />
            {/* <div style={{top: '-4%',left: '68%'}}>
                <Floating crown={Crown} text1="Full Stack" text2="Web Develpoer"/>
            </div>
            <div style={{top: '-4%',left: '68%'}}>
                <Floating crown={thumbup} text1="MERN" text2="Stack"/>
            </div> */}
        </div>
    </div>
  )
}

export default Intro
