import React from 'react'
import Humble from '../../images/humble.png';
import Glasses from "../../images/glasses.png";
import HeartEmoji from "../../images/heartemoji.png";
import './Services.css'
import Card from '../cards/Card';
import Resume from './resume.pdf';
import { themeContext } from '../../Context';
import { useContext } from 'react';
import { motion } from "framer-motion"



const Services = () => {
    const theme = useContext(themeContext);
    const darkMode = theme.state.darkMode;
    const transition = {duration: 1, type: 'spring'}
  return (
    <div className="services" id="About" class="about section" >
        {/* left side */}
        <div className="awesome">
            <span style={{color: darkMode ? 'white' : ''}}>Know more</span>
            <span>About me</span>
            {/* <span>I have used Java to learn my DSA and Algorithms, have learnt various topic including HashMap,Queue,Trees,<br/> Graphs,Recursion,Dynamic programming,Binary Search,Various Sorting algorithms. <br/></span> */}
            <ul>
                <li>Learnt DSA and Algorithms using Java</li>
                <li>Covered topics including HashMap, Queue, Trees,Graphs,<br />Recursion, Dynamic programming, Binary Search,Various Sorting algorithms.</li>
                <li>Spent 1000+ hours coding</li>
                <li>Received education from some of the best programmers </li>
                <li>Great team player with collaborations on 4+ projects</li>

            </ul>
            <a href="https://drive.google.com/file/d/1HskImUimONzyjUIkv1943AyCZ0MX08_F/view?usp=share_link" target="_blank" id="resume-link-2" download>
                <button className='button s-button'
                id="resume-button-2"
                >Download CV</button>
            </a>
            <div className='blur s-blurl' style={{background: "#ABF1FF94"}}></div>
        </div>
        {/* right side */}
        <div className="cards">
            <motion.div 
            whileInView={{left:'14rem'}}
            initial={{left:'25%'}}
            transition={transition}
            style={{left:'14rem'}}>
                <Card emoji={HeartEmoji} heading={"Languages & Libraries"}
                detail ={"Java, HTML, CSS, Javascript, React js, Node Js, Local Storage, API, Mongo DB"}/>
            </motion.div>
            <motion.div 
            whileInView={{left:'-4rem'}}
            initial={{left:'25%'}}
            transition={transition}
            style={{top:'12rem',left:"10rem"}}>
                <Card emoji={Glasses} heading={"DSA & Algorithm"}
                detail ={"JAVA 500+Questions, Coding 1000+ hours, "}/>
            </motion.div>
            <motion.div 
            whileInView={{left:'18rem'}}
            initial={{left:'25%'}}
            transition={transition}
            style={{top:"19rem",left:"12rem"}}>
                <Card emoji={Humble} heading={"Platforms Used"}
                detail ={"Leetcode, HackerRank, GeeksForGeek, Coding Ninjas, HackerEarth, Stack Overflow"}/>
            </motion.div>
        </div>
    </div>
  )
}

export default Services
