import React from 'react'
import "./Navbar.css"
import Toggle from './Toggle/Toggle'
import {Link} from 'react-scroll'

const Navbar = () => {
  return (
    <div className='n-wrapper' id="nav-menu">
        <div className='n-left'>
            <div className='n-name'>Vishwajeet</div>
            <Toggle/>
        </div>
        <div className='n-right'>
            <div className='n-list'>
                <ul style={{listStyleType: 'none'}}>
                    <Link spy={true} to='home' smooth={true}
                    activeClass="activeClass">
                    <li className='nav-li'>Home</li>
                    </Link>
                    <Link spy={true} to='About' smooth={true}  activeClass="activeClass">
                    <li className='nav-li'>About</li>
                    </Link>
                    <Link spy={true} to='skills' smooth={true} activeClass="activeClass">
                    <li className='nav-li'>Skills</li>
                    </Link>
                    <Link spy={true} to='projects' smooth={true}  activeClass="activeClass">
                    <li className='nav-li'>Projects</li>
                    </Link>
                    <Link spy={true} to='resume' smooth={true} activeClass="activeClass">
                    <li className='nav-li'>Resume</li>
                    </Link>   
                </ul>
            </div>
            <Link spy={true} to='contact' smooth={true}  activeClass="activeClass">
            <button className='button n-button'>
                Contact me
            </button>
            </Link> 
            
        </div>
      
    </div>
  )
}

export default Navbar
